#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long xa, ya, xb, yb, xc, yc;
        scanf("%lld %lld", &xa, &ya);
        scanf("%lld %lld", &xb, &yb);
        scanf("%lld %lld", &xc, &yc);
        bool ok = false;
        if (xa == xb && xb == xc) {
            if ((ya <= yb && yb <= yc) || (yc <= yb && yb <= ya)) ok = true;
        } else if (ya == yb && yb == yc) {
            if ((xa <= xb && xb <= xc) || (xc <= xb && xb <= xa)) ok = true;
        } else if ((xa == xb && yb == yc) || (ya == yb && xb == xc)) {
            ok = true;
        }
        printf("%s\n", ok ? "YES" : "NO");
    }
    return 0;
}

