import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            long xa = fs.nextLong();
            long ya = fs.nextLong();
            long xb = fs.nextLong();
            long yb = fs.nextLong();
            long xc = fs.nextLong();
            long yc = fs.nextLong();
            boolean ok = false;
            if (xa == xb && xb == xc) {
                if ((ya <= yb && yb <= yc) || (yc <= yb && yb <= ya)) ok = true;
            } else if (ya == yb && yb == yc) {
                if ((xa <= xb && xb <= xc) || (xc <= xb && xb <= xa)) ok = true;
            } else if ((xa == xb && yb == yc) || (ya == yb && xb == xc)) {
                ok = true;
            }
            sb.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

