#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        xa = int(next(it)); ya = int(next(it))
        xb = int(next(it)); yb = int(next(it))
        xc = int(next(it)); yc = int(next(it))
        ok = False
        if xa == xb == xc:
            if (ya <= yb <= yc) or (yc <= yb <= ya):
                ok = True
        elif ya == yb == yc:
            if (xa <= xb <= xc) or (xc <= xb <= xa):
                ok = True
        elif (xa == xb and yb == yc) or (ya == yb and xb == xc):
            ok = True
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

